mapper.select:
SELECT MAX(block_end) AS latestBlockEnd
FROM (

    /* 1. 즉시 차단: block_end_at 이 현재 일시 이후인 경우 */
    SELECT block_end_at AS block_end
    FROM LINE
    WHERE line_id     = #{lineId}
      AND block_end_at IS NOT NULL
      AND block_end_at  > #{now}

    UNION ALL

    /* 2. 반복 차단: 오늘 요일·현재 시각이 차단 구간에 포함되는 경우
       TIMESTAMP(CURDATE(), rbd.end_at) 로 LocalDateTime 형태로 변환하여 반환 */
    SELECT TIMESTAMP(CURDATE(), rbd.end_at) AS block_end
    FROM REPEAT_BLOCK rb
    INNER JOIN REPEAT_BLOCK_DAY rbd
        ON rb.repeat_block_id = rbd.repeat_block_id
       AND rbd.deleted_at IS NULL
    WHERE rb.line_id      = #{lineId}
      AND rb.is_active     = true
      AND rb.deleted_at    IS NULL
      AND rbd.day_of_week  = #{dayOfWeek}
      AND rbd.start_at    <= #{nowTime}
      AND rbd.end_at      >= #{nowTime}

) combined
